import requests
import json
from datetime import datetime


class Tools:

    BASE = "https://query1.finance.yahoo.com"
    HEADERS = {"User-Agent": "Mozilla/5.0"}

    def _quote(self, ticker: str) -> dict:
        url = f"{self.BASE}/v8/finance/chart/{ticker}"
        r = requests.get(
            url, headers=self.HEADERS, params={"interval": "1d", "range": "5d"}
        )
        return r.json()

    def _summary(self, ticker: str, modules: str) -> dict:
        headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36",
            "Accept": "application/json",
            "Referer": "https://finance.yahoo.com",
        }
        base = "https://query2.finance.yahoo.com"
        url = base + "/v11/finance/quoteSummary/" + ticker
        r = requests.get(url, headers=headers, params={"modules": modules})
        return r.json()

    def get_price(self, ticker: str) -> str:
        """
        Get real-time price for ANY ticker.
        Stocks: AAPL, TSLA, NVDA | Crypto: BTC-USD, ETH-USD
        Commodities: GC=F (Gold), CL=F (Oil), SI=F (Silver), NG=F (Gas)
        Forex: EURUSD=X, GBPUSD=X | Indices: ^GSPC, ^IXIC, ^DJI, ^VIX
        Bonds: ^TNX (10Y), ^TYX (30Y) | ETFs: SPY, QQQ, VTI
        """
        try:
            url = f"{self.BASE}/v8/finance/chart/{ticker}"
            r = requests.get(
                url, headers=self.HEADERS, params={"interval": "1d", "range": "5d"}
            ).json()
            meta = r["chart"]["result"][0]["meta"]
            return json.dumps(
                {
                    "ticker": ticker.upper(),
                    "price": meta.get("regularMarketPrice"),
                    "prev_close": meta.get("previousClose")
                    or meta.get("chartPreviousClose"),
                    "change_%": round(
                        (
                            (
                                meta.get("regularMarketPrice", 0)
                                - (
                                    meta.get("previousClose")
                                    or meta.get("chartPreviousClose", 0)
                                )
                            )
                            / (
                                meta.get("previousClose")
                                or meta.get("chartPreviousClose", 1)
                            )
                        )
                        * 100,
                        2,
                    ),
                    "day_high": meta.get("regularMarketDayHigh"),
                    "day_low": meta.get("regularMarketDayLow"),
                    "open": meta.get("regularMarketOpen"),
                    "volume": meta.get("regularMarketVolume"),
                    "52w_high": meta.get("fiftyTwoWeekHigh"),
                    "52w_low": meta.get("fiftyTwoWeekLow"),
                    "market_cap": meta.get("marketCap"),
                    "currency": meta.get("currency"),
                    "exchange": meta.get("exchangeName"),
                    "market_state": meta.get("marketState"),
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_stock_fundamentals(self, ticker: str) -> str:
        """Get full fundamentals: PE, EPS, margins, growth, dividends, analyst targets, beta."""
        try:
            data = self._summary(
                ticker, "summaryDetail,defaultKeyStatistics,financialData,assetProfile"
            )
            result = data.get("quoteSummary", {}).get("result", [{}])[0]
            sd = result.get("summaryDetail", {})
            ks = result.get("defaultKeyStatistics", {})
            fd = result.get("financialData", {})
            ap = result.get("assetProfile", {})

            def v(d, k):
                return (
                    d.get(k, {}).get("raw") if isinstance(d.get(k), dict) else d.get(k)
                )

            return json.dumps(
                {
                    "name": ap.get("longName")
                    or ap.get("companyOfficers", [{}])[0].get("name"),
                    "sector": ap.get("sector"),
                    "industry": ap.get("industry"),
                    "country": ap.get("country"),
                    "employees": ap.get("fullTimeEmployees"),
                    "website": ap.get("website"),
                    "description": ap.get("longBusinessSummary", "")[:400],
                    # Valuation
                    "pe_ratio": v(sd, "trailingPE"),
                    "forward_pe": v(sd, "forwardPE"),
                    "peg_ratio": v(ks, "pegRatio"),
                    "price_to_book": v(ks, "priceToBook"),
                    "price_to_sales": v(sd, "priceToSalesTrailing12Months"),
                    "enterprise_value": v(ks, "enterpriseValue"),
                    "ev_to_ebitda": v(ks, "enterpriseToEbitda"),
                    "ev_to_revenue": v(ks, "enterpriseToRevenue"),
                    # Per Share
                    "eps": v(ks, "trailingEps"),
                    "forward_eps": v(ks, "forwardEps"),
                    "book_value": v(ks, "bookValue"),
                    # Dividends
                    "dividend_yield": v(sd, "dividendYield"),
                    "dividend_rate": v(sd, "dividendRate"),
                    "payout_ratio": v(sd, "payoutRatio"),
                    "ex_dividend_date": v(sd, "exDividendDate"),
                    # Margins
                    "profit_margin": v(fd, "profitMargins"),
                    "operating_margin": v(fd, "operatingMargins"),
                    "gross_margin": v(fd, "grossMargins"),
                    "ebitda_margin": v(fd, "ebitdaMargins"),
                    # Growth
                    "revenue_growth": v(fd, "revenueGrowth"),
                    "earnings_growth": v(fd, "earningsGrowth"),
                    # Returns
                    "roe": v(fd, "returnOnEquity"),
                    "roa": v(fd, "returnOnAssets"),
                    # Liquidity
                    "current_ratio": v(fd, "currentRatio"),
                    "debt_to_equity": v(fd, "debtToEquity"),
                    "total_cash": v(fd, "totalCash"),
                    "total_debt": v(fd, "totalDebt"),
                    "free_cashflow": v(fd, "freeCashflow"),
                    # Risk
                    "beta": v(ks, "beta"),
                    "short_ratio": v(ks, "shortRatio"),
                    "short_%_float": v(ks, "shortPercentOfFloat"),
                    # Analyst
                    "analyst_target_mean": v(fd, "targetMeanPrice"),
                    "analyst_target_high": v(fd, "targetHighPrice"),
                    "analyst_target_low": v(fd, "targetLowPrice"),
                    "recommendation": fd.get("recommendationKey"),
                    "num_analysts": v(fd, "numberOfAnalystOpinions"),
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_price_history(self, ticker: str, period: str) -> str:
        """
        Get OHLCV price history for any ticker.
        period: 1d, 5d, 1mo, 3mo, 6mo, 1y, 2y, 5y, 10y, ytd, max
        """
        try:
            url = f"{self.BASE}/v8/finance/chart/{ticker}"
            r = requests.get(
                url, headers=self.HEADERS, params={"interval": "1d", "range": period}
            ).json()
            result = r["chart"]["result"][0]
            timestamps = result["timestamp"]
            ohlcv = result["indicators"]["quote"][0]
            return json.dumps(
                [
                    {
                        "date": datetime.utcfromtimestamp(timestamps[i]).strftime(
                            "%Y-%m-%d"
                        ),
                        "open": (
                            round(ohlcv["open"][i], 4) if ohlcv["open"][i] else None
                        ),
                        "high": (
                            round(ohlcv["high"][i], 4) if ohlcv["high"][i] else None
                        ),
                        "low": round(ohlcv["low"][i], 4) if ohlcv["low"][i] else None,
                        "close": (
                            round(ohlcv["close"][i], 4) if ohlcv["close"][i] else None
                        ),
                        "volume": ohlcv["volume"][i],
                    }
                    for i in range(len(timestamps))
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_income_statement(self, ticker: str) -> str:
        """Get annual income statement: revenue, gross profit, net income, EBITDA."""
        try:
            data = self._summary(
                ticker, "incomeStatementHistory,incomeStatementHistoryQuarterly"
            )
            result = data.get("quoteSummary", {}).get("result", [{}])[0]
            annual = result.get("incomeStatementHistory", {}).get(
                "incomeStatementHistory", []
            )
            quarterly = result.get("incomeStatementHistoryQuarterly", {}).get(
                "incomeStatementHistory", []
            )

            def parse(stmt):
                return {
                    k: v.get("raw") if isinstance(v, dict) else v
                    for k, v in stmt.items()
                }

            return json.dumps(
                {
                    "annual": [parse(s) for s in annual],
                    "quarterly": [parse(s) for s in quarterly],
                },
                default=str,
            )
        except Exception as e:
            return f"Error: {e}"

