    def get_dividends(self, ticker: str) -> str:
        """Get full dividend payment history."""
        try:
            url = f"{self.BASE}/v8/finance/chart/{ticker}"
            r = requests.get(
                url,
                headers=self.HEADERS,
                params={"interval": "1mo", "range": "max", "events": "dividends"},
            ).json()
            events = r["chart"]["result"][0].get("events", {}).get("dividends", {})
            return json.dumps(
                [
                    {
                        "date": datetime.utcfromtimestamp(v["date"]).strftime(
                            "%Y-%m-%d"
                        ),
                        "amount": v["amount"],
                    }
                    for v in sorted(
                        events.values(), key=lambda x: x["date"], reverse=True
                    )
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_splits(self, ticker: str) -> str:
