            r = requests.get(
                url,
                headers=self.HEADERS,
                params={"interval": "1mo", "range": "max", "events": "splits"},
            ).json()
            events = r["chart"]["result"][0].get("events", {}).get("splits", {})
            return json.dumps(
                [
                    {
                        "date": datetime.utcfromtimestamp(v["date"]).strftime(
                            "%Y-%m-%d"
                        ),
                        "ratio": f"{v['numerator']}/{v['denominator']}",
                    }
                    for v in sorted(
                        events.values(), key=lambda x: x["date"], reverse=True
                    )
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_options(self, ticker: str) -> str:
        """Get options chain: calls and puts with strike, price, IV, open interest."""
        try:
            url = f"{self.BASE}/v7/finance/options/{ticker}"
            r = requests.get(url, headers=self.HEADERS).json()
            result = r["optionChain"]["result"][0]
            expiry_dates = result.get("expirationDates", [])
            chain = result.get("options", [{}])[0]
            calls = chain.get("calls", [])[:15]
            puts = chain.get("puts", [])[:15]

            def parse_opt(o):
                return {
                    k: v.get("raw") if isinstance(v, dict) else v
                    for k, v in o.items()
                    if k
                    in [
                        "strike",
                        "lastPrice",
                        "bid",
                        "ask",
                        "volume",
                        "openInterest",
                        "impliedVolatility",
                        "inTheMoney",
                    ]
                }

            return json.dumps(
                {
                    "expiry": (
                        datetime.utcfromtimestamp(expiry_dates[0]).strftime("%Y-%m-%d")
                        if expiry_dates
                        else None
                    ),
                    "all_expiries": [
                        datetime.utcfromtimestamp(e).strftime("%Y-%m-%d")
                        for e in expiry_dates
                    ],
                    "calls": [parse_opt(c) for c in calls],
                    "puts": [parse_opt(p) for p in puts],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_stock_news(self, ticker: str) -> str:
        """Get latest news headlines for a ticker."""
        try:
            url = f"{self.BASE}/v1/finance/search"
            r = requests.get(
                url,
                headers=self.HEADERS,
                params={"q": ticker, "newsCount": 10, "quotesCount": 0},
            ).json()
            return json.dumps(
                [
                    {
                        "title": n.get("title"),
                        "publisher": n.get("publisher"),
                        "published": (
                            datetime.utcfromtimestamp(
                                n["providerPublishTime"]
                            ).strftime("%Y-%m-%d %H:%M")
                            if n.get("providerPublishTime")
                            else None
                        ),
                        "url": n.get("link"),
                        "summary": n.get("summary"),
                    }
                    for n in r.get("news", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_etf_info(self, ticker: str) -> str:
        """Get ETF details: expense ratio, NAV, returns, category. e.g. SPY, QQQ, VTI"""
        try:
            data = self._summary(
                ticker, "summaryDetail,defaultKeyStatistics,fundProfile,topHoldings"
            )
            result = data.get("quoteSummary", {}).get("result", [{}])[0]
            return json.dumps(result, default=str)
        except Exception as e:
            return f"Error: {e}"

    def get_market_indices(self) -> str:
        """Get live prices for all major global market indices."""
        indices = {
            "S&P 500": "^GSPC",
            "NASDAQ": "^IXIC",
            "Dow Jones": "^DJI",
            "Russell 2000": "^RUT",
            "VIX": "^VIX",
            "FTSE 100": "^FTSE",
            "DAX": "^GDAXI",
            "CAC 40": "^FCHI",
            "Nikkei 225": "^N225",
            "Hang Seng": "^HSI",
            "TSX Canada": "^GSPTSE",
            "ASX 200": "^AXJO",
        }
        results = []
        for name, symbol in indices.items():
            try:
                url = f"{self.BASE}/v8/finance/chart/{symbol}"
                r = requests.get(
                    url, headers=self.HEADERS, params={"interval": "1d", "range": "5d"}
                ).json()
                meta = r["chart"]["result"][0]["meta"]
                price = meta.get("regularMarketPrice", 0)
                prev = meta.get("previousClose") or meta.get("chartPreviousClose", 1)
                results.append(
                    {
                        "name": name,
                        "symbol": symbol,
                        "price": price,
                        "change_%": round(((price - prev) / prev) * 100, 2),
                    }
                )
            except:
                results.append({"name": name, "symbol": symbol, "error": "unavailable"})
        return json.dumps(results)

