    def get_forex_rates(self, pairs: str) -> str:
        """
        Get live forex rates. pairs = comma separated
        e.g. 'EURUSD=X,GBPUSD=X,USDJPY=X,USDCAD=X,AUDUSD=X,USDCHF=X'
        """
        results = []
        for pair in pairs.split(","):
            pair = pair.strip()
            try:
                url = f"{self.BASE}/v8/finance/chart/{pair}"
                r = requests.get(
                    url, headers=self.HEADERS, params={"interval": "1d", "range": "5d"}
                ).json()
                meta = r["chart"]["result"][0]["meta"]
                price = meta.get("regularMarketPrice", 0)
                prev = meta.get("previousClose") or meta.get("chartPreviousClose", 1)
                results.append(
                    {
                        "pair": pair,
                        "rate": round(price, 6),
                        "change_%": round(((price - prev) / prev) * 100, 4),
                        "day_high": meta.get("regularMarketDayHigh"),
                        "day_low": meta.get("regularMarketDayLow"),
                    }
                )
            except Exception as e:
                results.append({"pair": pair, "error": str(e)})
        return json.dumps(results)

